<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_finance','manage_invoices']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_invoices')||current_user_can($pdo,'manage_expenses');$projects=mb_project_options($pdo);if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$pdo->prepare("INSERT INTO mb_invoices (project_id,invoice_no,client_name,issue_date,due_date,amount,paid_amount,status,notes,created_by) VALUES (?,?,?,?,?,?,?,?,?,?)")->execute([$_POST['project_id']?:null,trim($_POST['invoice_no']??''),trim($_POST['client_name']??''),$_POST['issue_date']?:date('Y-m-d'),$_POST['due_date']?:null,(float)$_POST['amount'],(float)$_POST['paid_amount'],trim($_POST['status']??'unpaid'),trim($_POST['notes']??''),(int)$_SESSION['user_id']]);mb_set_success('Invoice saved.');}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_invoices WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Invoice deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('invoices.php');}$rows=$pdo->query("SELECT i.*,p.name project_name FROM mb_invoices i LEFT JOIN mb_projects p ON p.id=i.project_id ORDER BY i.issue_date DESC,i.id DESC")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Finance · Invoices','Invoices');?><?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card"><div class="mb-card-header"><strong>Invoices and billing</strong><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="invModal">New Invoice</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>No.</th><th>Project</th><th>Client</th><th>Issue</th><th>Due</th><th>Amount</th><th>Paid</th><th>Balance</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['invoice_no']?:$r['id'])?></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['client_name'])?></td><td><?=htmlspecialchars($r['issue_date'])?></td><td><?=htmlspecialchars($r['due_date'])?></td><td>₱<?=mb_money($r['amount'])?></td><td>₱<?=mb_money($r['paid_amount'])?></td><td>₱<?=mb_money($r['amount']-$r['paid_amount'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td><?php if($can):?><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete invoice?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="10" class="text-center text-muted py-4">No invoices yet.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="invModal"><div class="modal-dialog"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><div class="modal-header"><h5 class="modal-title">New Invoice</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><label class="form-label w-100">Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>"><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label class="form-label w-100">Invoice No.<input class="form-control" name="invoice_no"></label><label class="form-label w-100">Client<input class="form-control" name="client_name"></label><label class="form-label w-100">Issue Date<input class="form-control" type="date" name="issue_date" value="<?=date('Y-m-d')?>"></label><label class="form-label w-100">Due Date<input class="form-control" type="date" name="due_date"></label><label class="form-label w-100">Amount<input class="form-control" type="number" step="0.01" name="amount" value="0"></label><label class="form-label w-100">Paid<input class="form-control" type="number" step="0.01" name="paid_amount" value="0"></label><label class="form-label w-100">Status<input class="form-control" name="status" value="unpaid"></label><label class="form-label w-100">Notes<textarea class="form-control" name="notes"></textarea></label></div><div class="modal-footer"><button class="btn btn-primary">Save Invoice</button></div></form></div></div><?php mb_workspace_footer();?>